# Personal tracking template — maintained as a simple JSON file
# updated when reading newsletters each week

ADOPTION_TRACKER = {
    "speculative_decoding": {
        "first_seen": "2023-11-12",
        "newsletter": "Import AI",
        "stage": "tooling",          # preprint | discussion | tooling | mainstream
        "notes": "vLLM added support in 0.3; worth benchmarking for our inference stack",
        "action_taken": "benchmarked — 25% latency reduction on our P99 at batch=8"
    },
    "mixture_of_experts": {
        "first_seen": "2024-01-08",
        "newsletter": "Ahead of AI",
        "stage": "mainstream",
        "notes": "Mistral MoE released; now a standard option in open-weight models",
        "action_taken": "evaluated Mixtral 8x7B for our RAG pipeline — cost-competitive at our scale"
    },
}

def ideas_at_stage(tracker: dict, stage: str) -> list:
    return [name for name, data in tracker.items() if data["stage"] == stage]

print("Worth prototyping:", ideas_at_stage(ADOPTION_TRACKER, "discussion"))
print("Check if we're behind:", ideas_at_stage(ADOPTION_TRACKER, "mainstream"))
